patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..c1d4df995b5d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2029,6 +2029,22 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C - ((C2 - X) & Mask) where sub is nuw
+    Constant *MaskC;
+    BinaryOperator *Sub;
+    if (match(Op1, m_OneUse(m_c_And(m_BinOp(Sub), m_ImmConstant(MaskC)))) &&
+        Sub->getOpcode() == Instruction::Sub &&
+        match(Sub->getOperand(0), m_ImmConstant(C2)) &&
+        match(Sub->getOperand(1), m_Value(X))) {
+      // Compute C2 & Mask
+      Constant *C2Mask = ConstantExpr::getAnd(C2, MaskC);
+      // Compute C - (C2 & Mask)
+      Constant *Delta = ConstantExpr::getSub(C, C2Mask);
+      // (X & Mask) + Delta
+      Value *And = Builder.CreateAnd(X, MaskC);
+      return BinaryOperator::CreateAdd(And, Delta);
+    }
   }

   const APInt *Op0C;

